class ConstructionGenerator:
    """构造生成器 - 自动从 DEFINITIONS 生成构造语句"""

    def __init__(self):
        self.definitions = _get_definitions_dict()
        self.point_names = list("abcdefghijklmnopqrstuvwxyz")
        self.used_points: set = set()

    def reset(self):
        self.used_points = set()

    def _get_unused_points(self, count: int) -> List[str]:
        available = [p for p in self.point_names if p not in self.used_points]
        if len(available) < count:
            return []
        points = random.sample(available, count)
        self.used_points.update(points)
        return points

    def _get_unused_point(self) -> Optional[str]:
        points = self._get_unused_points(1)
        return points[0] if points else None

    def generate_construction(
        self, const_name: str, existing_points: Optional[List[str]] = None
    ) -> Tuple[List[str], List[str]]:
        """生成构造语句

        Args:
            const_name: 构造名称
            existing_points: 已存在的点列表（用于依赖构造）

        Returns:
            (构造语句列表, 新增的点列表)
        """
        if const_name not in self.definitions:
            return [], []

        definition = self.definitions[const_name]
        args_template = definition.get("args", [])
        constructions = []
        new_points = []

        if const_name not in CONSTRUCTION_DEPENDENCIES:
            return self._generate_simple_construction(const_name, args_template)

        dep_config = CONSTRUCTION_DEPENDENCIES[const_name]
        requires = dep_config.get("requires", [])

        if not requires:
            return self._generate_simple_construction(const_name, args_template)

        for req_const in requires:
            if req_const == "triangle":
                tri_points = self._get_unused_points(3)
                if not tri_points:
                    return [], []
                tri_stmt = f"{' '.join(tri_points)} = triangle"
                constructions.append(tri_stmt)
                new_points.extend(tri_points)
                existing_points = tri_points
            elif req_const == "circumcenter":
                if not existing_points or len(existing_points) < 3:
                    return [], []
                o = self._get_unused_point()
                if not o:
                    return [], []
                circum_stmt = f"{o} = circumcenter {o} {' '.join(existing_points[:3])}"
                constructions.append(circum_stmt)
                new_points.append(o)
                existing_points = existing_points + [o]

        if const_name in [
            "midpoint",
            "circumcenter",
            "orthocenter",
            "incenter",
            "foot",
            "angle_bisector",
        ]:
            if not existing_points:
                return [], []
            new_point = self._get_unused_point()
            if not new_point:
                return [], []
            triangle_args = dep_config.get("triangle_args", [0, 1, 2])
            args = [
                existing_points[i] for i in triangle_args if i < len(existing_points)
            ]
            stmt = f"{new_point} = {const_name} {new_point} {' '.join(args)}"
            constructions.append(stmt)
            new_points.append(new_point)

        elif const_name in ["on_line", "on_tline", "on_pline"]:
            if not existing_points:
                return [], []
            new_point = self._get_unused_point()
            if not new_point:
                return [], []
            triangle_args = dep_config.get("triangle_args", [0, 1, 2])
            args = [
                existing_points[i] for i in triangle_args if i < len(existing_points)
            ]
            stmt = f"{new_point} = {const_name} {new_point} {' '.join(args)}"
            constructions.append(stmt)
            new_points.append(new_point)

        elif const_name == "on_circle":
            if not existing_points or len(existing_points) < 4:
                return [], []
            new_point = self._get_unused_point()
            if not new_point:
                return [], []
            o = existing_points[3] if len(existing_points) > 3 else existing_points[0]
            a = existing_points[0]
            stmt = f"{new_point} = on_circle {new_point} {o} {a}"
            constructions.append(stmt)
            new_points.append(new_point)

        elif const_name == "on_circum":
            if not existing_points or len(existing_points) < 3:
                return [], []
            new_point = self._get_unused_point()
            if not new_point:
                return [], []
            stmt = (
                f"{new_point} = on_circum {new_point} {' '.join(existing_points[:3])}"
            )
            constructions.append(stmt)
            new_points.append(new_point)

        elif const_name == "intersection_ll":
            if not existing_points or len(existing_points) < 4:
                return [], []
            new_point = self._get_unused_point()
            if not new_point:
                return [], []
            args = [
                existing_points[i] for i in [0, 1, 1, 2] if i < len(existing_points)
            ]
            stmt = f"{new_point} = intersection_ll {new_point} {' '.join(args)}"
            constructions.append(stmt)
            new_points.append(new_point)

        else:
            return self._generate_simple_construction(const_name, args_template)

        return constructions, new_points

    def _generate_simple_construction(
        self, const_name: str, args_template: List[str]
    ) -> Tuple[List[str], List[str]]:
        """生成简单构造（无依赖）"""
        num_args = len(args_template)
        points = self._get_unused_points(num_args)
        if not points:
            return [], []

        if const_name in ["triangle", "r_triangle", "iso_triangle"]:
            stmt = f"{' '.join(points)} = {const_name}"
        elif const_name in ["parallelogram", "rectangle", "square", "trapezoid"]:
            stmt = f"{' '.join(points)} = {const_name} {' '.join(points)}"
        elif const_name == "free":
            stmt = f"{points[0]} = free"
        elif const_name == "segment":
            stmt = f"{points[0]} {points[1]} = segment"
        else:
            stmt = f"{' '.join(points)} = {const_name} {' '.join(points)}"

        return [stmt], points

    def get_available_constructions(self) -> List[str]:
        """获取所有可用的构造名称"""
        return list(self.definitions.keys())

    def get_constructions_with_predicates(self) -> List[str]:
        """获取所有会产生谓词的构造名称"""
        result = []
        for name, defn in self.definitions.items():
            if defn.get("predicates"):
                result.append(name)
        return result


class ControlledReasoningEngine:
    """受控推理引擎 - 每步只产生一个新命题"""

    def __init__(self):
        self.definitions = _get_definitions_dict()
        self.rules = _get_rules_list()
        self.predicates = {}
        self.predicate_list = []
        self.proof_steps = []
        self.level = 0

    def reset(self):
        self.predicates = {}
        self.predicate_list = []
        self.proof_steps = []
        self.level = 0

    def is_valid_predicate(self, pred):
        """检查谓词是否合理"""
        parts = pred.strip().split()
        if len(parts) < 3:
            return False
        name = parts[0]
        args = parts[1:]

        if name in ["para", "perp"]:
            if len(args) >= 4:
                line1 = sorted([args[0], args[1]])
                line2 = sorted([args[2], args[3]])
                if line1 == line2:
                    return False
        elif name in ["cong"]:
            if len(args) >= 4:
                seg1 = sorted([args[0], args[1]])
                seg2 = sorted([args[2], args[3]])
                if seg1 == seg2:
                    return False
        return True

    def normalize(self, pred):
        parts = pred.strip().split()
        if not parts:
            return ()
        name = parts[0]
        args = parts[1:]

        if name in ["coll", "cyclic", "ncoll"]:
            return (name, tuple(sorted(args)))
        elif name in ["para", "perp"]:
            if len(args) >= 4:
                line1 = tuple(sorted([args[0], args[1]]))
                line2 = tuple(sorted([args[2], args[3]]))
                if line1 <= line2:
                    return (name, line1 + line2)
                else:
                    return (name, line2 + line1)
            return (name, tuple(args))
        elif name in ["cong", "eqratio"]:
            if len(args) >= 4:
                seg1 = tuple(sorted([args[0], args[1]]))
                seg2 = tuple(sorted([args[2], args[3]]))
                if seg1 <= seg2:
                    return (name, seg1 + seg2)
                else:
                    return (name, seg2 + seg1)
            return (name, tuple(args))
        elif name == "midp":
            if len(args) >= 3:
                point = args[0]
                seg = tuple(sorted([args[1], args[2]]))
                return (name, (point,) + seg)
            return (name, tuple(args))
        else:
            return (name, tuple(args))

    def add(self, pred):
        key = self.normalize(pred)
        if key not in self.predicates:
            self.predicates[key] = pred
            self.predicate_list.append(pred)
            return True
        return False

    def expand_construction(self, construction):
        if " = " not in construction:
            return []
        _points_part, const_part = construction.split(" = ", 1)
        const_parts = const_part.strip().split()
        const_name = const_parts[0] if const_parts else ""
        const_args = const_parts[1:] if len(const_parts) > 1 else []
        if const_name not in self.definitions:
            return []
        definition = self.definitions[const_name]
        predicates = []
        arg_names = definition.get("args", [])
        var_mapping = {}
        for i, arg_name in enumerate(arg_names):
            if i < len(const_args):
                var_mapping[arg_name] = const_args[i]
        for template in definition.get("predicates", []):
            parts = template.split()
            result = [parts[0]]
            valid = True
            for arg in parts[1:]:
                if arg in var_mapping:
                    result.append(var_mapping[arg])
                elif len(arg) == 1 and arg.isalpha():
                    result.append(arg)
                else:
                    valid = False
                    break
            if valid:
                pred = " ".join(result)
                predicates.append(pred)
        return predicates

    def step_forward(self):
        """向前推理一步，只返回一个随机选择的新命题（优化版：预先过滤已存在的结论和不合理的谓词）"""
        self.level += 1
        valid_matches = []
        for rule in self.rules:
            matches = self._find_all_matches(rule)
            for m in matches:
                conclusion = self._apply(rule, m)
                if conclusion and self.is_valid_predicate(conclusion):
                    normalized = self.normalize(conclusion)
                    if normalized not in self.predicates:
                        valid_matches.append((rule, m, conclusion))
        if not valid_matches:
            return []
        chosen_rule, chosen_match, conclusion = random.choice(valid_matches)
        self.predicates[self.normalize(conclusion)] = conclusion
        self.predicate_list.append(conclusion)
        premises = self._get_matched_premises(chosen_rule, chosen_match)
        step = ProofStep(premises, conclusion, chosen_rule["name"], self.level)
        self.proof_steps.append(step)
        return [step]

    def _find_all_matches(self, rule):
        matches = []
        premises = rule["premises"]
        if len(premises) == 1:
            for pred in self.predicate_list:
                mapping = self._match_single(premises[0], pred, {})
                if mapping is not None:
                    matches.append((mapping, [pred]))
        elif len(premises) == 2:
            for pred in self.predicate_list:
                mapping = self._match_single(premises[0], pred, {})
                if mapping is None:
                    continue
                for pred2 in self.predicate_list:
                    if pred2 == pred:
                        continue
                    mapping2 = self._match_single(premises[1], pred2, mapping.copy())
                    if mapping2 is not None:
                        matches.append((mapping2, [pred, pred2]))
        return matches

    def _match_single(self, template, actual, mapping):
        """Match a template predicate against an actual predicate.

        Args:
            template: Template predicate with variable placeholders (e.g., "coll A B C")
            actual: Actual predicate with concrete values (e.g., "coll x y z")
            mapping: Existing variable mapping from previous matches

        Returns:
            Updated mapping if match succeeds, None otherwise
        """
        t_parts = template.split()
        a_parts = actual.split()

        # Must have same number of parts
        if len(t_parts) != len(a_parts):
            return None

        # Predicate names must match
        if t_parts[0] != a_parts[0]:
            return None

        new_mapping = mapping.copy()

        # Match each argument position
        for t, a in zip(t_parts[1:], a_parts[1:]):
            if t in new_mapping:
                # Variable already mapped - must be consistent
                if new_mapping[t] != a:
                    return None
            else:
                # New variable - add to mapping
                new_mapping[t] = a

        return new_mapping

    def _apply(self, rule, match_data):
        mapping = match_data[0]
        conclusion = rule["conclusion"]
        parts = conclusion.split()
        result = [parts[0]]
        for arg in parts[1:]:
            if arg in mapping:
                result.append(mapping[arg])
            else:
                return ""
        return " ".join(result)

    def _get_matched_premises(self, _rule, match_data):
        return match_data[1]


def generate_random_construction():
    """随机生成构造语句 - 自动从 DEFINITIONS 选择，生成多个构造以获得更多初始谓词"""
    generator = ConstructionGenerator()
    generator.reset()
    available = generator.get_constructions_with_predicates()
    if not available:
        return []

    all_constructions = []
    all_new_points = []

    # 生成1-3个构造
    num_constructions = random.randint(1, 3)

    for _ in range(num_constructions):
        chosen = random.choice(available)
        constructions, new_points = generator.generate_construction(
            chosen, all_new_points if all_new_points else None
        )
        if constructions:
            all_constructions.extend(constructions)
            all_new_points.extend(new_points)

    return all_constructions if all_constructions else []


def generate_training_data():
    """生成训练数据主函数"""
    print("=" * 60)
    print("几何证明训练数据生成器 (受控推理 + 自动构造)")
    print("=" * 60)
    print("\n配置参数:")
    print(f"  最小步数: {MIN_STEPS}")
    print(f"  最大步数: {MAX_STEPS}")
    print(f"  目标数量: {NUM_PROBLEMS}")
    print(f"  输出文件: {OUTPUT_FILE}")

    generator = ConstructionGenerator()
    available = generator.get_constructions_with_predicates()
    print(f"\n可用构造类型 ({len(available)} 种):")
    for const in available:
        defn = _get_definitions_dict().get(const, {})
        desc = defn.get("description", "")
        preds = defn.get("predicates", [])
        print(f"  - {const}: {desc} ({len(preds)} 个谓词)")

    print()

    engine = ControlledReasoningEngine()
    valid_data = []
    attempts = 0
    max_attempts = 1000

    print("开始生成数据...\n")

    while len(valid_data) < NUM_PROBLEMS and attempts < max_attempts:
        attempts += 1
        engine.reset()
        constructions = generate_random_construction()
        if not constructions:
            continue
        setup_predicates = []
        for const in constructions:
            expanded = engine.expand_construction(const)
            for pred in expanded:
                if engine.add(pred):
                    setup_predicates.append(pred)
        if not setup_predicates:
            continue
        target_steps = random.randint(MIN_STEPS, MAX_STEPS)
        for _ in range(target_steps):
            new_steps = engine.step_forward()
            if not new_steps:
                break
        total_steps = len(engine.proof_steps)
        if attempts <= 5:
            print(f"  [调试] 尝试 {attempts}: 推理了 {total_steps} 步")
        if MIN_STEPS <= total_steps <= MAX_STEPS and engine.proof_steps:
            goal = engine.proof_steps[-1].conclusion
            proof_data = ProofData(
                problem_name=f"controlled_{len(valid_data)}",
                problem_statement="; ".join(constructions) + f" ? {goal}",
                constructions=constructions,
                goal=goal,
                proof_steps=engine.proof_steps,
                is_solved=True,
                setup_predicates=setup_predicates,
            )
            valid_data.append(proof_data)
            print(f"  [✓] 问题 {len(valid_data)}: {total_steps} 步, 目标: {goal}")
        else:
            if attempts % 50 == 0:
                print(
                    f"  已尝试 {attempts} 次, 已收集 {len(valid_data)}/{NUM_PROBLEMS} (上次: {total_steps}步)"
                )

    print("\n" + "=" * 60)
    print("生成统计:")
    print(f"  总尝试数: {attempts}")
    print(f"  有效数据: {len(valid_data)}")
    if valid_data:
        step_counts = [len(d.proof_steps) for d in valid_data]
        print(f"  步数范围: {min(step_counts)} - {max(step_counts)}")
        print(f"  平均步数: {sum(step_counts)/len(step_counts):.1f}")
        data_list = [d.to_training_format() for d in valid_data]
        with open(OUTPUT_FILE, "w", encoding="utf-8") as f:
            json.dump(data_list, f, ensure_ascii=False, indent=2)
        print(f"\n已保存到: {OUTPUT_FILE}")
    else:
        print("\n警告: 没有生成有效数据!")
    print("=" * 60)
    return valid_data


def verify_generated_data():
    """验证生成的训练数据"""
    print("\n" + "=" * 60)
    print("验证生成的训练数据")
    print("=" * 60)
    if not os.path.exists(OUTPUT_FILE):
        print("错误: 数据文件不存在!")
        return
    with open(OUTPUT_FILE, "r", encoding="utf-8") as f:
        data = json.load(f)
    print(f"\n共加载 {len(data)} 条数据")
    print(f"步数要求: {MIN_STEPS} - {MAX_STEPS} 步\n")
    all_valid = True
    for item in data:
        step_count = len(item.get("proof_steps", []))
        is_valid = MIN_STEPS <= step_count <= MAX_STEPS
        status = "[OK]" if is_valid else "[FAIL]"
        if not is_valid:
            all_valid = False
        print(
            f"  {status} {item['problem_name']}: {step_count} 步, 目标: {item['goal']}"
        )
    print("\n" + "=" * 60)
    if all_valid:
        print("验证结果: 所有数据都符合步数要求 [OK]")
    else:
        print("验证结果: 存在不符步数要求的数据 [FAIL]")
    print("=" * 60)


if __name__ == "__main__":
    generate_training_data()
    verify_generated_data()
